package main
import (
    "fmt"
    "errors"
)

func divide(a, b int) (int, error) {
    if b == 0 {
        // Create and return our custom error!
        return 0, errors.New("cannot divide by zero, friend!")
    }
    return a / b, nil
}

func main() {
    result, err := divide(10, 0)
    if err != nil {
        fmt.Println("Oops:", err)
    } else {
        fmt.Println("Result:", result)
    }
}
